const TEST_LIMIT = 1;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function sgTimestamp() {
  const now = new Date();
  const singaporeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Singapore' }));
  const yyyy = singaporeTime.getFullYear();
  const mm = String(singaporeTime.getMonth() + 1).padStart(2, '0');
  const dd = String(singaporeTime.getDate()).padStart(2, '0');
  const hh = String(singaporeTime.getHours()).padStart(2, '0');
  const min = String(singaporeTime.getMinutes()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

function extractDriveFolderId(url) {
  const raw = clean(url);
  if (!raw) return '';
  const match = raw.match(/\/folders\/([a-zA-Z0-9_-]+)/);
  if (match) return match[1];
  return raw;
}

function padUnitPart(value) {
  const raw = clean(value);
  if (!raw) return '';
  if (/^\d+$/.test(raw) && raw.length === 1) return `0${raw}`;
  return raw;
}

function unitSuffix(level, unit) {
  const lvl = padUnitPart(level);
  const unt = padUnitPart(unit);
  if (lvl && unt) return `#${lvl}-${unt}`;
  if (lvl && !unt) return `#${lvl}`;
  if (!lvl && unt) return `#-${unt}`;
  return '';
}

function safeJoin(parts, separator = ' ') {
  return parts.map(clean).filter(Boolean).join(separator).replace(/\s+/g, ' ').trim();
}

function propertyDisplayName(row) {
  const segment = clean(row['Property Segment']).toLowerCase();
  const projectName = clean(row['Project Name']);
  const blk = clean(row['Blk']);
  const streetName = clean(row['Street Name']);
  const suffix = unitSuffix(row['Level'], row['Unit']);

  if (segment === 'hdb') return safeJoin([safeJoin([blk, streetName]), suffix]);
  return safeJoin([projectName || safeJoin([blk, streetName]) || streetName, suffix]);
}

function privacySafeFloor(level) {
  const raw = clean(level);
  const n = Number(raw);
  if (!Number.isFinite(n)) return raw ? `Level ${raw}` : 'Floor not stated';

  if (n >= 30) return 'very high floor';
  if (n >= 20) return 'high floor';
  if (n >= 10) return 'mid-high floor';
  if (n >= 4) return 'mid floor';
  return 'low floor';
}

function formatPrice(row) {
  const raw = clean(row['Price']);
  if (!raw) return '';
  const num = Number(raw.replace(/[$,\s]/g, ''));
  if (!Number.isFinite(num)) return raw;
  return '$' + num.toLocaleString('en-SG');
}

function pgDocTitle(row) {
  return `PG Listing Pack - ${propertyDisplayName(row)}`;
}

function buildDraftBody(row) {
  const now = sgTimestamp();
  const saleRent = clean(row['Sale / Rent']);
  const segment = clean(row['Property Segment']);
  const display = propertyDisplayName(row);
  const priceLabel = saleRent === 'Rent' ? 'Asking Rent' : 'Asking Price';
  const privacyFloor = privacySafeFloor(row['Level']);

  return [
    `PG Listing Pack Draft`,
    ``,
    `Property: ${display}`,
    `Generated: ${now}`,
    ``,
    `Source Record`,
    `Property Record ID: ${clean(row['Property Record ID'])}`,
    `Source Sheet: ${clean(row['Source Sheet'])}`,
    `Source Tab: ${clean(row['Source Tab'])}`,
    `Clarity Route: ${clean(row['Clarity Route'])}`,
    ``,
    `Property Details`,
    `Sale / Rent: ${saleRent}`,
    `Property Segment: ${segment}`,
    `Project Name: ${clean(row['Project Name'])}`,
    `Block: ${clean(row['Blk'])}`,
    `Street Name: ${clean(row['Street Name'])}`,
    `Level / Unit: ${clean(row['Level'])}-${clean(row['Unit'])}`,
    `Privacy-safe floor wording for PG copy: ${privacyFloor}`,
    `Type: ${clean(row['Type'])}`,
    `Size: ${clean(row['Size'])} sqft`,
    `Bedrooms: ${clean(row['No. of BR'])}`,
    `${priceLabel}: ${formatPrice(row)}`,
    `PSF: ${clean(row['PSF'])}`,
    `Tenure: ${clean(row['Tenure'])}`,
    ``,
    `Location / Enrichment`,
    `Postal Code: ${clean(row['Postal Code'])}`,
    `OneMap Matched Address: ${clean(row['OneMap Matched Address'])}`,
    `District: ${clean(row['District'])}`,
    `URA Batch: ${clean(row['URA Batch'])}`,
    ``,
    `Asset Folder`,
    `${clean(row['Asset Folder Link'])}`,
    ``,
    `Draft PG Blurb Placeholder`,
    `[Module 4B will insert the AI-generated PropertyGuru blurb here.]`,
    ``,
    `Review Checklist`,
    `- Do not reveal exact unit number in final PG copy.`,
    `- Use privacy-safe floor wording instead of exact level where suitable.`,
    `- Verify bedrooms, bathrooms, floorplan and photos before publishing.`,
    `- Avoid overclaiming view, privacy, condition, or stack attributes unless verified.`,
    `- Final copy should follow the approved PG format: concise opening paragraph, dash-led selling points, and CTA.`,
    ``,
  ].join('\n');
}

const output = [];

for (const item of items) {
  const row = item.json;

  const route = clean(row['Clarity Route']);
  const automationEligible = clean(row['Automation Eligible']).toLowerCase();
  const pgStatus = clean(row['PG Pack Status']).toLowerCase();
  const existingPgLink = clean(row['PG Blurb Output Link']);
  const assetFolderLink = clean(row['Asset Folder Link']);
  const assetFolderId = extractDriveFolderId(assetFolderLink);

  const isActiveRoute = route === 'Active Listing' || route === 'Active Listing + CMA';

  if (!isActiveRoute) continue;
  if (automationEligible !== 'yes') continue;
  if (!assetFolderLink || !assetFolderId) continue;
  if (existingPgLink) continue;
  if (pgStatus && pgStatus !== 'pending' && pgStatus !== 'error') continue;

  output.push({
    json: {
      ...row,
      'PG Doc Title': pgDocTitle(row),
      'PG Pack Draft Body': buildDraftBody(row),
      'Asset Folder ID': assetFolderId,
      'PG Pack Last Updated': sgTimestamp(),
      'PG Pack Notes': 'Selected for Module 4A PG pack draft shell test run',
    },
  });

  if (output.length >= TEST_LIMIT) break;
}

return output;

