}

const selectedRow = $('Select 1 Eligible PG Pack Row').first().json;
const createdDoc = $('Create Google Doc - PG Pack Draft').first().json || {};
const movedDoc = items[0]?.json || createdDoc;

const docId = clean(movedDoc.id || movedDoc.documentId || createdDoc.id || createdDoc.documentId);
const docTitle = clean(createdDoc.title || movedDoc.name || selectedRow['PG Doc Title']);
const docLink = clean(movedDoc.webViewLink || createdDoc.webViewLink) || (docId ? `https://docs.google.com/document/d/${docId}/edit` : '');

if (!docId && !docLink) {
  return [{
    json: {
      'Source Key': selectedRow['Source Key'],
      'Property Record ID': selectedRow['Property Record ID'],
      'PG Pack Status': 'Error',
      'PG Pack Last Updated': sgTimestamp(),
      'PG Pack Review Status': 'Needs Review',
      'PG Pack Notes': 'Google Doc creation did not return a document ID or link',
    },
  }];
}

return [{
  json: {
    'Source Key': selectedRow['Source Key'],
    'Property Record ID': selectedRow['Property Record ID'],
    'PG Pack Status': 'Draft Created',
    'PG Blurb Output Link': docLink,
    'PG Pack Last Updated': sgTimestamp(),
    'PG Pack Review Status': 'Needs Review',
    'PG Pack Notes': `Created PG pack draft shell: ${docTitle}`,
  },
}];
